let timeoutId;

window.addEventListener("mousemove", function (e) {
  document.querySelectorAll(".magical").forEach((node) => {
    if (!node.querySelector(".show")) {
      node.insertAdjacentHTML("beforeend", "<div class='show'></div>");
    }

    const rect = node.getBoundingClientRect();
    const offsetX = e.clientX - rect.left;
    const offsetY = e.clientY - rect.top;
    node.style.setProperty("--mouse-x", `${offsetX}px`);
    node.style.setProperty("--mouse-y", `${offsetY}px`);

    const hoverLayer = node.querySelector(".show");
    if (!hoverLayer) return;
    const isInside =
      offsetX >= 0 &&
      offsetX <= node.clientWidth &&
      offsetY >= 0 &&
      offsetY <= node.clientHeight;
    hoverLayer.style.opacity = isInside ? "1" : "0";
  });
});

document.addEventListener("DOMContentLoaded", function () {
  const emailCopied = document.getElementById("emailCopied");
  if (emailCopied) {
    emailCopied.addEventListener("click", async function () {
      clearTimeout(timeoutId);
      const text = this.textContent || "";

      let copied = false;
      if (navigator.clipboard && navigator.clipboard.writeText) {
        try {
          await navigator.clipboard.writeText(text);
          copied = true;
        } catch (_) {}
      }

      if (!copied) {
        const input = document.createElement("input");
        input.value = text;
        document.body.appendChild(input);
        input.select();
        copied = document.execCommand("copy");
        document.body.removeChild(input);
      }

      if (copied) {
        const copiedHint = document.getElementsByClassName("copied")[0];
        if (copiedHint) {
          copiedHint.style.opacity = "1";
          timeoutId = setTimeout(function () {
            copiedHint.style.opacity = "0";
          }, 1000);
        }
      }
    });
  }

  initMenuToggle();
});

function initMenuToggle() {
  const menuExpand = document.getElementById("menu-expand");
  const menuExpandChild = document.getElementById("menu-expand-child");
  const menuPanel = document.getElementById("menu-panel");

  if (!menuExpand || !menuExpandChild || !menuPanel) {
    return;
  }

  const menuIcon = menuExpandChild.querySelector(".menu-icon");
  const mobileMedia = window.matchMedia("(max-width: 768px)");
  let isMenuOpen = false;

  const setIconState = (open) => {
    if (!menuIcon) return;
    menuIcon.style.transition = "transform .35s";
    menuIcon.style.transform = open ? "rotate(45deg)" : "rotate(0deg)";
  };

  const syncPanelState = () => {
    if (mobileMedia.matches) {
      menuPanel.style.left = "";
      if (isMenuOpen) {
        menuPanel.classList.add("is-open");
        menuPanel.hidden = false;
      } else {
        menuPanel.classList.remove("is-open");
        menuPanel.hidden = true;
      }
      return;
    }

    menuPanel.classList.remove("is-open");
    menuPanel.hidden = true;
    menuPanel.style.transition = "left .35s";
    menuPanel.style.left = "100vw";
  };

  const openMenu = () => {
    isMenuOpen = true;
    menuExpand.classList.add("active");
    setIconState(true);
    syncPanelState();
  };

  const closeMenu = () => {
    isMenuOpen = false;
    menuExpand.classList.remove("active");
    setIconState(false);
    syncPanelState();
  };

  menuExpand.addEventListener("click", function (e) {
    e.stopPropagation();
    if (isMenuOpen) {
      closeMenu();
    } else {
      openMenu();
    }
  });

  menuPanel.addEventListener("click", function (e) {
    e.stopPropagation();
  });

  document.addEventListener("click", function () {
    if (isMenuOpen) {
      closeMenu();
    }
  });

  document.addEventListener("keydown", function (e) {
    if (e.key === "Escape" && isMenuOpen) {
      closeMenu();
    }
  });

  window.addEventListener("resize", function () {
    if (!mobileMedia.matches && isMenuOpen) {
      closeMenu();
      return;
    }
    syncPanelState();
  });

  syncPanelState();
}
